// Script pour un logger de frappe sur Snegli Clavier
// Ce script enregistrera les frappes au clavier et les affichera dans la console

document.addEventListener('keydown', function(event) {
    // Récupérer le code de la touche pressée
    const key = event.key;
    const code = event.code;
    const timestamp = new Date().toISOString();

    // Afficher les informations dans la console
    console.log(`[Snegli Logger] ${timestamp} - Touche pressée : ${key} (Code : ${code})`);
});
